import { Terrain } from "./terrain.js";
// All of this code is generated by ai for system tests / not meant for using in the actual game, so it may be a bit rough around the edges. It creates a test stage with multiple levels of terrain for testing purposes.
export function buildTestStage() {
    const WORLD_LENGTH = 7000;
    const SEGMENTS = 35;
    const SEGMENT_WIDTH = 200;
    const GROUND_Y = 350;

    // Solid start area
    new Terrain({ x: -400, y: GROUND_Y }, { x: 1000, y: 100 }, "#3e2723", false);

    // Continuous floor with very occasional small gaps
    let currentX = 600;
    while (currentX < WORLD_LENGTH) {
        const width = 400 + Math.random() * 600;
        const gap = Math.random() > 0.9 ? 120 : 0; // Very few gaps

        new Terrain(
            { x: currentX, y: GROUND_Y },
            { x: width, y: 500 },
            "#4e342e",
            false
        );
        currentX += width + gap;
    }

    // Well-spaced platforms
    for (let i = 0; i < WORLD_LENGTH; i += 400) {
        const x = i + 800;
        if (x > WORLD_LENGTH - 600) break;

        // Choice of height levels to keep it organized
        const heights = [GROUND_Y - 120, GROUND_Y - 240, GROUND_Y - 360];
        const hIndex = Math.floor(Math.random() * heights.length);
        const platY = heights[hIndex];
        const platWidth = 150 + Math.random() * 100;
        
        // Alternate between solid and platform types
        const isPlatform = Math.random() > 0.3;
        const hue = (i / 20) % 360;
        const color = isPlatform ? `hsl(${hue}, 60%, 45%)` : `hsl(${hue}, 30%, 25%)`;

        new Terrain(
            { x, y: platY },
            { x: platWidth, y: 25 },
            color,
            isPlatform
        );

        // Add a secondary slightly offset platform if enough space
        if (Math.random() > 0.6) {
            new Terrain(
                { x: x + 200, y: platY - 120 },
                { x: 120, y: 20 },
                `hsl(${hue + 20}, 50%, 40%)`,
                true
            );
        }
    }

    // Ceiling (non-platform) - consistent height
    new Terrain(
        { x: -500, y: -600 },
        { x: WORLD_LENGTH + 1500, y: 150 },
        "#1a1a1a",
        false
    );

    // Obstacles/Walls to jump over
    for (let i = 1200; i < WORLD_LENGTH - 1000; i += 1500) {
        new Terrain(
            { x: i, y: GROUND_Y - 80 },
            { x: 60, y: 80 },
            "#212121",
            false
        );
    }

    // THE ENDING: Large finish tower
    const finishX = WORLD_LENGTH;
    // Ground foundation for end
    new Terrain({ x: finishX, y: GROUND_Y }, { x: 1000, y: 500 }, "#2c1e1a", false);
    // The "Goal" Tower
    new Terrain({ x: finishX + 400, y: GROUND_Y - 400 }, { x: 200, y: 400 }, "gold", false);
    // Victory banner/roof
    new Terrain({ x: finishX + 350, y: GROUND_Y - 450 }, { x: 300, y: 50 }, "darkred", false);
    
    console.log("Stage built! Reach the Gold Tower at x:", finishX + 400);
}